import React, { useState } from "react";

import ChatBox from "./components/ChatBox";
import Selects from "./components/seletorIAS";
import PerguntaResposta from "./components/PerguntaResposta";
import Header from "./header";

import { prepararPergunta } from "./utils/manipulacoesString";
import {
  chamarChatGPT,
  chamarGemini,
  chamarGrok,
  chamarDeepseek,
} from "./utils/APIchats";

import "./App.css";
import ModalConfig from "./components/ModalConfig";

export default function App() {
  const [IA1, setIA1] = useState("");
  const [IA2, setIA2] = useState("");
  const [arbitro, setarbitro] = useState("");

  const [open, isOpen] = useState(false);

  const [pergunta, setPergunta] = useState("");
  const [resposta, setResposta] = useState("");
  const [respostaArbitro, setRespostaArbitro] = useState("");
  const [respostaPronta, setRespostaPronta] = useState(false);
  const [trocarVerdadeiro, settrocarVerdadeiro] = useState(false);
  const [respostaIA1, setRespostaIA1] = useState("");
  const [respostaIA2, setRespostaIA2] = useState("");

  const [prefixo, setPrefixo] = useState(
    "responda como se fosse um estudante do ensino médio Técnico de uma forma resumida que não passe de 5 linhas sem gírias antigas, humanizado, sem girias e sem emojis esta seguinte pergunta: ",
  );

  // ================================
  // FIA (mantido como array)
  // ================================
  let fia = [];
  fia["Grok"] = (perguntaMontada, isArbiter) =>
    chamarGrok(perguntaMontada, isArbiter);

  fia["Gemini"] = (perguntaMontada, isArbiter) =>
    chamarGemini(perguntaMontada, isArbiter);

  fia["Chatgpt"] = (perguntaMontada, isArbiter) =>
    chamarChatGPT(perguntaMontada, isArbiter);

  fia["deepseek"] = (perguntaMontada, isArbiter) =>
    chamarDeepseek(perguntaMontada, isArbiter);

  // ================================
  // Chama a IA pelo nome
  // ================================
  async function chamarFuncaoPorNome(
    nome,
    perguntaPreparada,
    isArbiter = false,
  ) {
    const fSelect = fia[nome];

    if (!fSelect) {
      console.error("IA não encontrada:", nome);
      return "";
    }

    const resp = await fSelect(perguntaPreparada, isArbiter);
    return resp?.resp ?? "";
  }

  // ================================
  // Fluxo principal
  // ================================
  async function fluxoComunicacao() {
    if (!IA1 || !IA2 || !arbitro) {
      alert("Por favor selecione todas as IAs e o árbitro");
      return;
    }

    setRespostaPronta(false);

    // Pergunta base
    const perguntaPreparada = prepararPergunta(pergunta, prefixo);

    // Chamadas das IAs
    const RIA1 = await chamarFuncaoPorNome(IA1, perguntaPreparada);
    const RIA2 = await chamarFuncaoPorNome(IA2, perguntaPreparada);

    setRespostaIA1(RIA1);
    setRespostaIA2(RIA2);

    // Texto para o árbitro
    const textoArbitro = `${pergunta}
      Resposta primeira IA: ${RIA1}
      Resposta segunda IA: ${RIA2}
      Verifique se existe algum tipo de erro, alucinações ou falta de informações.
      Faça uma análise curta, sem passar de 20 linhas.`;

    // Chamada do árbitro
    const RArbitro = await chamarFuncaoPorNome(arbitro, textoArbitro, true);

    setRespostaArbitro(RArbitro);
    setRespostaPronta(true);
  }

  return (
    <div>
      <ModalConfig
        className="ModalApp"
        mudarPergunta={setPrefixo}
        open={open}
        close={() => isOpen(false)}
      />

      <div className="caixa">
        <Header abrirModal={() => isOpen(true)} />

        <div className="caixaPrincipal">
          <ChatBox
            pronto={respostaPronta}
            respostaIA1={respostaIA1}
            respostaIA2={respostaIA2}
            respostaArbitro={respostaArbitro}
          />

          <Selects
            IA1={IA1}
            IA2={IA2}
            arbitro={arbitro}
            trocarIA1={setIA1}
            trocarIA2={setIA2}
            trocarArbitro={setarbitro}
          />
        </div>

        <PerguntaResposta
          quest={pergunta}
          answer={resposta}
          setquest={setPergunta}
          setanswer={setResposta}
          checkbox={trocarVerdadeiro}
          bloquearResposta={settrocarVerdadeiro}
          fluxoComunicacao={fluxoComunicacao}
        />
      </div>
    </div>
  );
}
